            base:  [p(-0.30, -0.05), p(0.0, -0.22), p(0.0, 0.30), p(-0.22, 0.20)],
            crane: [p(-0.18, -0.02), p(0.0, -0.10), p(0.0, 0.28), p(-0.20, 0.20)],
            tone:  PaperTone(r: 0.93, g: 0.42, b: 0.38),
