            flat:  [p(-0.06, -0.30), p(0.06, -0.30), p(0.04, 0.02), p(-0.04, 0.02)],
            base:  [p(-0.05, -0.40), p(0.03, -0.40), p(0.06, -0.04), p(-0.02, -0.02)],
