            base:  [p(-0.04, -0.46), p(0.06, -0.42), p(0.02, -0.36)],
            crane: [p(-0.02, -0.56), p(0.14, -0.50), p(0.04, -0.46)],
            tone:  PaperTone(r: 0.86, g: 0.30, b: 0.30),
