            axis: (x: 1.0, y: 0.4, z: 0.0),
            litPhase: 0.95
        ),
        // 6 — tail
        CraneFacet(
            id: 6,
            flat:  [p(-0.04, 0.30), p(0.04, 0.30), p(0.0, 0.42)],
